{% block header %}Detailed Report{% endblock %}

{% block content %}
<h2>Data Table</h2>
{% import "macros.html" as macros %}
{{ macros.render_table(data, thresholds) }}

<h2>Summary Statistics</h2>
<ul>
    {% for col, stats in summary.items() %}
        <li><strong>{{ col|capitalize }}:</strong> min={{ stats.min }}, max={{ stats.max }}, avg={{ stats.avg }}</li>
    {% endfor %}
</ul>
{% endblock %}

{% block footer %}
Generated on {{ generation_time }}
{% endblock %}
""",
}


# ---------------------------------------------------------------------------
# Helper: compute simple summary statistics (used by the detailed report example)
# ---------------------------------------------------------------------------
def _compute_summary(data: List[Dict[str, Any]]) -> Dict[str, Dict[str, float]]:
    """
    Return a dict mapping column name → {min, max, avg}.
    Only numeric columns are considered.
    """
    from collections import defaultdict

    numeric_columns: Dict[str, List[float]] = defaultdict(list)

    for row in data:
        for col, value in row.items():
            if isinstance(value, (int, float)):
                numeric_columns[col].append(float(value))

    summary: Dict[str, Dict[str, float]] = {}
    for col, values in numeric_columns.items():
        if values:
            summary[col] = {
                "min": min(values),
                "max": max(values),
                "avg": sum(values) / len(values),
            }
    return summary


